INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('locality-6f0ba476-moex-00015', 'locality-6f0ba476', 'locality-6f0ba476-moex-114-9b7ab1bb', 'sub-locality-6f0ba476-02', NULL, 'single_choice', '50 歲甲某日在陽明山賞花時，遺失一只銀灰色 C 牌功能性手錶，由於該只手錶是甲 20 歲生日 時，當時還在世之母親所贈，甲非常珍惜。甲即在網路上將該錶之照片與特徵公布，並透過廣告 之方式表示，若有人拾獲該只手錶，將懸賞新臺幣（下同）5,000元。下列敘述何者正確？', '["甲所發布之廣告，性質為要約引誘", "若乙不知廣告之內容，偶然拾獲甲之手錶，乙得向甲請求5,000元之報酬", "懸賞廣告之性質，依民法規定，係為單獨行為", "懸賞廣告不得撤回"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:00+00:00", "source_pdf_sha1": "7278b8eb62a0", "answer_pdf_sha1": "42e3c5c0be26", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "312", "s": "0701", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('locality-6f0ba476-moex-00016', 'locality-6f0ba476', 'locality-6f0ba476-moex-114-9b7ab1bb', 'sub-locality-6f0ba476-02', NULL, 'single_choice', '甲對乙有新臺幣100萬元之債權，乙與丙訂立債務承擔契約，由丙承擔乙之債務。下列敘述何者 正確？', '["乙與丙訂立之債務承擔契約，非經甲承認，對甲不生效力", "乙與丙訂立之債務承擔契約，非經甲承認，契約不生效力", "於乙與丙之債務承擔契約成立時，丙即成為甲之債務人", "於乙與丙之債務承擔契約生效時，丙即成為甲之債務人"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:00+00:00", "source_pdf_sha1": "7278b8eb62a0", "answer_pdf_sha1": "42e3c5c0be26", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "312", "s": "0701", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('locality-6f0ba476-moex-00017', 'locality-6f0ba476', 'locality-6f0ba476-moex-114-9b7ab1bb', 'sub-locality-6f0ba476-02', NULL, 'single_choice', '甲、乙、丙將三人共有之不動產出租於丁，但履行期屆至後，三人遲未將約定出租之該不動產交 付於丁使用。下列敘述何者正確？', '["經丁定期催告其履約後，甲等三人屆期仍未交付時，丁得解除租賃契約", "經丁定期催告後，甲等三人仍未交付時，丁得終止租賃契約", "丁僅向甲為解除之意思表示，即生解除之效力", "丁僅向乙為終止之意思表示，即生終止之效力"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:00+00:00", "source_pdf_sha1": "7278b8eb62a0", "answer_pdf_sha1": "42e3c5c0be26", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "312", "s": "0701", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('locality-6f0ba476-moex-00018', 'locality-6f0ba476', 'locality-6f0ba476-moex-114-9b7ab1bb', 'sub-locality-6f0ba476-02', NULL, 'single_choice', '甲向乙借貸新臺幣（下同）10萬元，乙表示同意。下列敘述何者正確？', '["乙將10萬元移轉於甲時，消費借貸契約成立", "因甲與乙之約定，消費借貸契約成立，甲基於契約，得請求乙交付10萬元", "金錢消費借貸，應以書面為之", "乙須將10萬元移轉於甲，因此金錢消費借貸為處分行為"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:00+00:00", "source_pdf_sha1": "7278b8eb62a0", "answer_pdf_sha1": "42e3c5c0be26", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "312", "s": "0701", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('locality-6f0ba476-moex-00019', 'locality-6f0ba476', 'locality-6f0ba476-moex-114-9b7ab1bb', 'sub-locality-6f0ba476-02', NULL, 'single_choice', '甲、乙共有A地500坪，應有部分均等，甲因對丙借款，為擔保該債務，雙方約定：「甲將A地 靠馬路邊之250坪設定普通抵押權於丙」。下列敘述何者錯誤？', '["共有人得自由處分其應有部分，該處分係指處分行為，亦包含設定負擔", "甲丙間約定之債權行為，有效", "如認甲丙間約定係就A地之特定一部分設定抵押權，則該設定之物權行為有效", "若甲丙間約定經解釋雙方當事人真意，係認甲欲以其應有部分設定抵押權於丙，則就應有部分 設定行為，仍屬有效"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:00+00:00", "source_pdf_sha1": "7278b8eb62a0", "answer_pdf_sha1": "42e3c5c0be26", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "312", "s": "0701", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('locality-6f0ba476-moex-00020', 'locality-6f0ba476', 'locality-6f0ba476-moex-114-9b7ab1bb', 'sub-locality-6f0ba476-02', NULL, 'single_choice', '同一抵押物有多數普通抵押權者，抵押權人得依民法規定，處分抵押權之次序。關於抵押權次序 之處分，下列敘述何者錯誤？', '["因抵押權次序處分而受利益之抵押權人，亦得實行調整前次序在先之抵押權", "抵押權人為特定後次序抵押權人之利益，得拋棄其抵押權之次序", "抵押權次序之處分，非經登記，不生效力", "抵押權人得自由調整其可優先受償之分配額"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:00+00:00", "source_pdf_sha1": "7278b8eb62a0", "answer_pdf_sha1": "42e3c5c0be26", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "312", "s": "0701", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('locality-6f0ba476-moex-00021', 'locality-6f0ba476', 'locality-6f0ba476-moex-114-9b7ab1bb', 'sub-locality-6f0ba476-02', NULL, 'single_choice', '下列何種權利之設定，並未違反物權法定主義之規定？', '["設定承租人對租用之房屋有物權效力之優先購買權", "設定將質物移轉占有於質權人之不動產質權", "設定在他人建物上以建築或其他工作物為目的之普通地上權", "設定以自己不動產供自己其他不動產便宜之用之不動產役權"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:00+00:00", "source_pdf_sha1": "7278b8eb62a0", "answer_pdf_sha1": "42e3c5c0be26", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "312", "s": "0701", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('locality-6f0ba476-moex-00022', 'locality-6f0ba476', 'locality-6f0ba476-moex-114-9b7ab1bb', 'sub-locality-6f0ba476-02', NULL, 'single_choice', '間接占有人，乃占有媒介關係之一方當事人。下列何者非屬占有媒介關係？', '["附條件買賣關係", "寄託關係", "租賃關係", "抵押權關係"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:00+00:00", "source_pdf_sha1": "7278b8eb62a0", "answer_pdf_sha1": "42e3c5c0be26", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "312", "s": "0701", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('locality-6f0ba476-moex-00023', 'locality-6f0ba476', 'locality-6f0ba476-moex-114-9b7ab1bb', 'sub-locality-6f0ba476-02', NULL, 'single_choice', '下列何者是習慣法上所創設之物權？', '["借名登記契約下，借名人之管理使用權", "最高限額抵押權", "讓與擔保", "共有人間之應有部分優先承購權"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:00+00:00", "source_pdf_sha1": "7278b8eb62a0", "answer_pdf_sha1": "42e3c5c0be26", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "312", "s": "0701", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('locality-6f0ba476-moex-00024', 'locality-6f0ba476', 'locality-6f0ba476-moex-114-9b7ab1bb', 'sub-locality-6f0ba476-02', NULL, 'single_choice', '甲將其所有A地設定普通地上權於乙，無支付地租之約定。甲復將其所有B地設定10年期限之 普通地上權於丙，有支付地租之約定。甲又將其所有C地設定未定有期限之普通地上權於丁，有 支付地租之約定。依民法規定，下列敘述何者正確？', '["丙得支付未到期之2年分地租後，拋棄其地上權", "丁得支付3年分地租後，拋棄其地上權", "丙拋棄其地上權時，應於1年前通知甲", "乙得隨時拋棄其地上權"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:00+00:00", "source_pdf_sha1": "7278b8eb62a0", "answer_pdf_sha1": "42e3c5c0be26", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "312", "s": "0701", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財稅行政"}'::jsonb, NULL)
